 1	import type { FC } from 'react';
 2	import SectionHeading from 'src/components/headers/SectionHeading';
 3	import { useForkliftTranslation } from 'src/utils/i18n';
 4	
 5	import LoadingSuspend from '@components/LoadingSuspend';
 6	import { NetworkMapModelGroupVersionKind, type V1beta1NetworkMap } from '@kubev2v/types';
 7	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 8	import { PageSection } from '@patternfly/react-core';
 9	
10	import { ConditionsSection } from '../../components/ConditionsSection/ConditionsSection';
11	import DetailsSection from '../../components/DetailsSection/DetailsSection';
12	import { MapsSection } from '../../components/MapsSection/MapsSection';
13	import { ProvidersSection } from '../../components/ProvidersSection/ProvidersSection';
14	
15	type NetworkMapDetailsTabProps = {
16	  name: string;
17	  namespace: string;
18	};
19	
20	export const NetworkMapDetailsTab: FC<NetworkMapDetailsTabProps> = ({ name, namespace }) => {
21	  const { t } = useForkliftTranslation();
22	
23	  const [obj, loaded, loadError] = useK8sWatchResource<V1beta1NetworkMap>({
24	    groupVersionKind: NetworkMapModelGroupVersionKind,
25	    isList: false,
26	    name,
27	    namespace,
28	    namespaced: true,
29	  });
30	
31	  return (
32	    <LoadingSuspend obj={obj} loaded={loaded} loadError={loadError}>
33	      <PageSection variant="light" className="forklift-page-section--details">
34	        <SectionHeading text={t('Network map details')} />
35	        <DetailsSection obj={obj} />
36	      </PageSection>
37	
38	      <PageSection variant="light" className="forklift-page-section">
39	        <SectionHeading text={t('Providers')} />
40	        <ProvidersSection obj={obj} />
41	      </PageSection>
42	
43	      <PageSection variant="light" className="forklift-page-section">
44	        <SectionHeading text={t('Map')} />
45	        <MapsSection obj={obj} />
46	      </PageSection>
47	
48	      <PageSection variant="light" className="forklift-page-section">
49	        <SectionHeading text={t('Conditions')} />
50	        <ConditionsSection conditions={obj?.status?.conditions ?? []} />
51	      </PageSection>
52	    </LoadingSuspend>
53	  );
54	};

